import{_ as b,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"子弹族","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/6.一次性血统/子弹族.md","filePath":"4.资源分区/1.血统与训练/6.一次性血统/子弹族.md"}'),s={name:"4.资源分区/1.血统与训练/6.一次性血统/子弹族.md"};function o(d,p,l,_,i,c){return e(),a("div",null,[...p[0]||(p[0]=[r("h1",{id:"子弹族",tabindex:"-1"},[t("子弹族 "),r("a",{class:"header-anchor",href:"#子弹族","aria-label":'Permalink to "子弹族"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风023元旦版")])])],-1),n('<h1 id="子弹族-1" tabindex="-1">子弹族 <a class="header-anchor" href="#子弹族-1" aria-label="Permalink to &quot;子弹族&quot;">​</a></h1><p>（出自游戏 《挺进地牢》）</p><p>星系中流传着这样一个传说，在某个遥远星球上，屹立着一座冷峻的城堡，<br> 直到有一天，一股极具破坏力的力量突破了极乐之地，突袭了这片安逸之地<br> 这股力量摧毁了城堡，但城堡所留下的古老残骸却成功留下了这股力量降临时的纪念品——抹除过去之枪。<br> 而一群将它奉为信仰神明的神迹的教徒也随之到来，并重新修复了这座城堡，并遵循神明所制定的规则，考验想要使用抹除过去之枪的“囚犯”。</p><p>这把枪吸引着星系各处的人来此，也许是为了奖赏，又或者是为了抹除自己的过去。<br> 但他们想要离开地牢，则必须......</p><p>特殊的，本资源提供的血统均为一次性血统。</p><p>==========<br> 子弹怪<br> 价格：D+600<br> 购买前提：建卡智力不高于1<br> 城堡的原住民之一，他们是简单的生物，但警惕而忠诚。经历那场力量所带来的浩劫后，他们成为了那力量来源神明的信徒。</p><p>【活子弹】：购买此血统后，你会不可避免的变成一颗...子弹，没错，跟人大的子弹，你的种族变更为【子弹】，进食对你来说不再是必须项。<br> 成为子弹后，你体内的火药变成了一大危险因素，这令你获得【火焰易伤2】，但好在你的弹壳身体还算结实，你因此获得2点天生防御，在耐力上获得1点内在加值。</p><p>另外，由于你变成了子弹，一些原本令人类感到不适的事物对你失效或影响大打折扣，只要你想你总能休息一会。这视为你获得自适应短休和自适应长休。<br> 当你进行自适应短休或长休时，在画风上为你收起所有子弹族特征，看起来就是颗立起或放平的大号子弹。</p><p>【好子弹】：每个合格的子弹怪，在被投入到地牢阻击囚犯深入探索之前，都会经过合格的射击训练——起码得让你学会瞄准和按扳机。<br> 你的射击技能提高1级（仍需遵循建卡规则），再选择左轮/冲锋枪/步枪 专业之一增加1级，若选择专业已达到3级，则改为获得其相关检定的1附加成功。<br> 如果你选择提升冲锋枪专业，则你再获得一条红头巾作为装饰物。</p><p>【子弹构造】：变成子弹后，无机体的你比有机体要耐造多了，如果仅是缺失一些部件和身体破损还要不了你的性命，只要你填装进身体的灵魂还在。<br> 你的伤势不再会自动恶化，但如果你拥有【潮湿】状态，则本效果失效。</p><p>特殊的，购买本血统时你也可以选择“霰弹怪”或“狙击子弹怪”两种子弹怪变体<br> 若这么做，则选择获得提高的专业变为霰弹枪或狙击枪，并且血统名字“子弹怪”变更为“霰弹怪”或“狙击子弹怪”</p><p>特殊的特殊，选择购买“霰弹怪”变体时，你需要从红蓝绿三种外壳颜色中选择一种，仅在外观上有所不同。<br> （PS：红色霰弹怪和绿色的变异霰弹怪中意M1887霰弹枪，而蓝色霰弹怪更中意温切斯特霰弹枪。）</p><p>=====【子弹怪/霰弹怪/狙击子弹怪 下属强化】=====<br> 枪战老手<br> 价格：D+500<br> 在地牢中会成长的并非只有地牢囚犯，子弹族们同样拥有在枪战中学习并成长的能力——前提是他们得活下来。<br> 你的身上还留着枪战的痕迹，这些没能打倒你的伤痕，都将令你更加坚韧。你增加3点天生防御，并且获得基于天生防御的【防弹】。</p><p>霰弹，死的<br> 价格：D+750<br> 购买前提：拥有“霰弹怪”血统<br> 无论霰弹怪的大小，喜好，枪法，作战方式如何，在被击倒时引爆自己对地牢囚犯发动最后一击是他们压箱底的一招。<br> 以一个标准动作使用，你主动激发体内的火药随后爆体而亡，倾泻出大量大号弹丸杀伤以自己为中心半径15m内的敌方目标，反射豁免，命中后追加3点附加伤害。<br> 这次攻击组成为【敏捷+射击+专业-霰弹枪+辅助专业-弹道学】，并具有【9加骰】。使用后不可复活。（但是会留个金属弹壳）</p><p>大师级瞄准<br> 价格：D+750<br> 购买前提：拥有“狙击子弹怪”血统<br> 狙击子弹手里的狙击步枪适合高精度射击，作为地牢里最新出现的子弹族成员，很难说子弹族们在变得像囚犯使用的武器，还是他们对囚犯的武器越来越熟悉。<br> 作为子弹族里最新的成员，对囚犯的射击技术了解的也最快。你的瞄准上限增加2点，使用远程武器瞄准后进行的下一次攻击额外获得5点高速。</p><p>被遗忘者<br> 价格：D+500<br> 购买前提：拥有“子弹怪”血统，或拥有“霰弹怪”血统<br> 在第一膛室与第二膛室之间，布局着城堡的下水道系统——虽然早已废弃，但不妨碍子弹族把一些子弹怪或其他子弹关进这里。<br> 时间一久，这些被遗弃或囚禁在下水道的子弹族当中还健在的部分，已经适应了下水道那充满有害物质的环境，继续履行他们阻碍地牢囚犯的责任。</p><p>【毒素满满】：长期生活在充满有害物质的下水道中，你已经习惯与这些有害物质相处，与他们井水不犯河水。这视为你拥有免疫C级毒素的能力</p><p>【快快奔跑】：在为数不多与地牢囚犯的交战中，你认识到跑快点冲向囚犯再攻击，可比慢悠悠走过去要有效多了。你的移动速度增加10m，并获得2点额外的先攻。</p><p>幽灵子弹<br> 价格：C+1250<br> 子弹族们在被摧毁后，其装填的灵魂会回到第四膛室，在这里他们会得到重新装填，并作为幽灵形态重新出击，回到他们曾经战斗过的枪膛继续战斗。<br> 虽然这幅灵魂身体既不能隐形，也不能免物伤，更没法穿墙，但最基本的传送能力他们还是会的。你的外观变为通体白色，底部和体内镂空的子弹。<br> 由于你体内的火药不复存在，你失去从血统获得的【火焰易伤2】</p><p>【隐入空气】：幽灵子弹最基础的能力，在进行移动时，表现为你的身体逐渐变淡隐去，完全消失后在指定地点重新显形。这是一个C级【传送移动】能力。</p><p>【飘浮子弹】：虽然幽灵子弹做不到自由飞翔，但脚不沾地的贴着地面飘着还是做得到的，这视为一个免疫C级困难地形效果，并且你免疫坠落伤害。</p><p>披风子弹怪：<br> 价格：D+850<br> 购买前提：建卡智力不高于1<br> 昔日的英雄，今日的叛徒！子弹怪中大大的异端，面对地牢囚犯不但不帮助同胞，反而选择帮助他们，甚至用的是一把剑而不是枪！<br> 特殊的，当一名轮回者成为披风子弹怪时，其将一直被其他子弹族敌视（除了其他披风子弹怪）</p><p>【披风子弹】：购买此血统后，你会不可避免的变成一颗...子弹，没错，跟人大的子弹，还带个红披风呢，你的种族变更为【子弹】，进食对你来说不再是必须项。<br> 成为子弹后，你体内的火药变成了一大危险因素，这令你获得【火焰易损2】，但好在你的弹壳身体还算结实，你因此获得2点天生防御，在耐力上获得1内在加值。</p><p>另外，由于你变成了子弹，一些原本令人类感到不适的事物对你失效或影响大打折扣，只要你想你总能休息一会。这视为你获得自适应短休和自适应长休，<br> 当你进行自适应短休或长休时，在画风上为你收起所有子弹族特征，看起来就是颗立起或放平的大号子弹。</p><p>【孤独子弹】：也许当时你犹豫了，但你最后还是继承了老子弹的遗愿，拿起了你们的祖传武器，前往讨伐占领城堡的邪恶国王加农，并成功击退了它。<br> 购买本血统时，你的武技技能提高1级（仍需遵循建卡规则），选择剑/肉搏 专业增加1级，若选择专业已达到3级，则改为获得其相关检定的1附加成功。</p><p>【子弹构造】：变成子弹后，无机体的你比有机体要耐造多了，如果仅是缺失一些部件和身体破损还要不了你的性命，只要你填装进身体的灵魂还在。<br> 你的伤势不再会自动恶化，但如果你拥有【潮湿】状态，则本效果失效。</p><p>【我也是子弹！】：跟你的同胞不同，你深刻认识到自己也是颗子弹的事实，用舍身一击给予目标致命一击，才是子弹的本事啊！<br> 现在你的弹头（脑袋）视为武器伤害为3L的天生武器，使用一般天生武器的攻击检定，在画风上为你蓄势一撞，一头创向目标。</p><p>=====【披风子弹怪下属强化】=====<br> 好运傍身<br> 价格：D+500<br> 总所周知，地牢囚犯在拿到足够强大的枪械后往往有一键清空房间的能力，并且他们为了无伤也不会吝惜他们的弹药。<br> 好在你足够幸运，不但遇到了地牢囚犯不止五次，还每次都在他们注意到你对他们没有恶意前幸存下来过一共五次。</p><p>你的机运检定获得1点加值，并且获得2点天生防御与基于天生防御的【防弹】。</p><p>翻滚技巧<br> 价格：D+500<br> 你觉得光是以头创人伤害不够高，所以你在跟着地牢囚犯到达城堡大厅后，顺带向他们请教了翻滚的技巧，并把它结合到你的撞击中。<br> 虽然你的体态决定了你没法真的翻个跟斗，但好歹你学到了如何前扑并躲避子弹。不用心疼你的底火，他们随时间会自己回来的。</p><p>【子弹头槌】：你跑起来了，虽然会伴随乒乒乓乓的响声，但凭你子弹的体格这一下撞上去可不轻。现在冲锋时即使你的冲锋距离不够，也能吃满冲锋加值。<br> 如果使用你的天生武器（弹头）进行冲锋攻击，在画风上变为你助跑后触发底火舍身一跃，伴随清脆的一声，一头创向目标后以头抢地尔。</p><p>【纵身一跃】：你跑起来了，虽然会伴随乒乒乓乓的响声，现在你可跳跃移动，可以准确的控制跳跃的落点和距离而无需检定。<br> 在画风上为你触发底火舍身一跃后，伴随清脆的一声以头抢地尔，落在地上弹起后顺势起身站稳。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',34)])])}const m=b(s,[["render",o]]);export{f as __pageData,m as default};
